"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[57966],{92911:e=>{e.exports=JSON.parse('{"tag":{"label":"genetics","permalink":"/docs/tags/genetics","allTagsPath":"/docs/tags","count":3,"items":[{"id":"guinea-pigs/breeds-and-genetics/know-your-guinea-pig-breeds","title":"Know Your Guinea Pig Breeds","description":"From the sleek and smooth to the curly and long-haired, guinea pigs come in a wonderful variety of breeds, each with its own unique look and grooming needs. While personality is individual, some...","permalink":"/docs/guinea-pigs/breeds-and-genetics/know-your-guinea-pig-breeds"},{"id":"guinea-pigs/breeds-and-genetics/coat-color-genetics","title":"Understanding Guinea Pig Coat Color Genetics","description":"Guinea pigs are known for their stunning diversity of coat colors and patterns, from solid black to intricate brindles and dalmatians. This variety isn\'t random; it\'s the result of a fascinating and complex world of genetics. Understanding the basics of coat color inheritance is not only interesting for curious owners but is also critical for responsible breeding and rescue advocacy to prevent serious genetic health problems.","permalink":"/docs/guinea-pigs/breeds-and-genetics/coat-color-genetics"},{"id":"guinea-pigs/breeds-and-genetics/lethalwhite","title":"Understanding Lethal White Guinea Pigs","description":"Guinea pigs are beloved companions known for their sweet nature, vocal personalities, and varied appearances. But within the world of guinea pig care, there\u2019s a little-known and serious condition that deserves more awareness\u2014lethal white syndrome.","permalink":"/docs/guinea-pigs/breeds-and-genetics/lethalwhite"}],"unlisted":false}}')}}]);